(15, 11, 5, 1, 'Exam Routine', 'what about our examinations? why it\'s late', '2023', 1, NULL, NULL, '2026-03-02', '2026-03-11 18:09:29', '2026-03-20 07:39:48', NULL, 'HOD'),
(17, 11, 2, 1, 'Food', 'I would like to report a complaint regarding the food provided in the canteen during the ongoing exam period. Exams are a crucial time for students, requiring focus, energy, and good health. Unfortunately, the quality of food in the canteen has been unsatisfactory during this period. The meals are often cold, not fresh, or undercooked.\r\n\r\nDuring exams, students rely on proper nutrition to stay alert and perform well. Poor food quality can negatively affect concentration, stamina, and overall well-being.\r\n\r\nI kindly request the concerned authority to monitor the canteen services and ensure that fresh, hygienic, and properly cooked food is provided to students during exams.', '2023', 1, NULL, NULL, '2026-03-15', '2026-03-11 18:18:38', '2026-03-21 06:33:19', NULL, 'HOD'),
(18, 10, 4, 3, 'Internet Issue', 'I would like to report an issue regarding the poor internet connectivity in the university. The internet is often very slow and frequently disconnects, making it difficult for students to access online learning materials, digital libraries, and submit assignments. Since many courses depend on online resources, this problem is affecting students’ learning and academic activities. I kindly request the concerned department to improve the internet service so that students can study and complete their work without interruption.', '2023', 1, NULL, NULL, '2026-03-12', '2026-03-12 02:14:21', '2026-03-12 02:28:38', 'Your complaint has been solved now', 'DeptAdmin'),
(22, 10, 4, 1, 'Internet Issue', 'I would like to report an issue regarding the poor internet connectivity in the university. The internet is often very slow and frequently disconnects, making it difficult for students to access online learning materials, digital libraries, and submit assignments. Since many courses depend on online resources, this problem is affecting students’ learning and academic activities. I kindly request the concerned department to improve the internet service so that students can study and complete their work without interruption.', '2023', 1, NULL, NULL, '2026-03-09', '2026-03-13 05:13:12', '2026-03-21 06:33:19', NULL, 'HOD'),
(23, 10, 4, 3, 'Internet Issue', 'I would like to report an issue regarding the poor internet connectivity in the university. The internet is often very slow and frequently disconnects, making it difficult for students to access online learning materials, digital libraries, and submit assignments. Since many courses depend on online resources, this problem is affecting students’ learning and academic activities. I kindly request the concerned department to improve the internet service so that students can study and complete their work without interruption.', '2023', 1, NULL, NULL, '2026-03-06', '2026-03-20 07:44:23', '2026-03-20 16:00:01', 'Your complaint has been solved.\r\nThank you', 'DeptAdmin'),
(24, 10, 2, 1, 'lalala', 'lalala', '2024', 1, NULL, NULL, '2026-03-03', '2026-03-20 16:17:27', '2026-03-20 16:17:27', NULL, 'DeptAdmin'),
(25, 10, 2, 1, 'lalala', 'lalala', '2024', 1, NULL, NULL, '2026-03-03', '2026-03-20 16:17:35', '2026-03-20 16:17:35', NULL, 'DeptAdmin'),
